package test.rice.parse;

import main.rice.node.APyNode;
import main.rice.node.PyBoolNode;
import main.rice.node.PyDictNode;
import main.rice.node.PyIntNode;
import main.rice.node.PyListNode;
import main.rice.parse.ConfigFile;
import main.rice.parse.ConfigFileParser;
import main.rice.parse.InvalidConfigException;
import org.junit.jupiter.api.Test;

import java.util.List;

import static org.junit.jupiter.api.Assertions.assertEquals;
import static org.junit.jupiter.api.Assertions.assertInstanceOf;

class ConfigFileParserAgentTest {

    @Test
    void parsesAssignmentAliasFieldNames() throws InvalidConfigException {
        String json = """
            {
                "fname": "f",
                "types": ["int"],
                "exDomain": ["2~4"],
                "ranDomain": ["[8,9]"],
                "numRand": 3
            }
            """;

        ConfigFile config = new ConfigFileParser().parse(json);

        assertEquals("f", config.getFuncName());
        assertEquals(3, config.getNumRand());
        APyNode<?> node = config.getNodes().get(0);
        assertInstanceOf(PyIntNode.class, node);
        assertEquals(List.of(2, 3, 4), node.getExDomain());
        assertEquals(List.of(8, 9), node.getRanDomain());
    }

    @Test
    void parsesNestedListAndDictDomainsInPreorder() throws InvalidConfigException {
        String json = """
            {
                "fname": "f",
                "types": ["list(dict(int:bool))"],
                "exhaustive domain": ["0~1;0~1;1~2;0~1"],
                "random domain": ["1~2;0~2;3~4;[0,1]"],
                "num random": 0
            }
            """;

        ConfigFile config = new ConfigFileParser().parse(json);

        APyNode<?> outer = config.getNodes().get(0);
        assertInstanceOf(PyListNode.class, outer);
        assertEquals(List.of(0, 1), outer.getExDomain());
        assertEquals(List.of(1, 2), outer.getRanDomain());

        APyNode<?> dict = outer.getLeftChild();
        assertInstanceOf(PyDictNode.class, dict);
        assertEquals(List.of(0, 1), dict.getExDomain());
        assertEquals(List.of(0, 1, 2), dict.getRanDomain());

        APyNode<?> key = dict.getLeftChild();
        assertInstanceOf(PyIntNode.class, key);
        assertEquals(List.of(1, 2), key.getExDomain());
        assertEquals(List.of(3, 4), key.getRanDomain());

        APyNode<?> value = dict.getRightChild();
        assertInstanceOf(PyBoolNode.class, value);
        assertEquals(List.of(0, 1), value.getExDomain());
        assertEquals(List.of(0, 1), value.getRanDomain());
    }
}

package main.rice;

import main.rice.parse.ConfigFile;
import main.rice.parse.ConfigFileParser;
import main.rice.parse.InvalidConfigException;
import main.rice.basegen.BaseSetGenerator;
import main.rice.concisegen.ConciseSetGenerator;
import main.rice.test.TestCase;
import main.rice.test.TestResults;
import main.rice.test.Tester;

import java.io.IOException;
import java.nio.file.Files;
import java.nio.file.Path;
import java.util.List;
import java.util.Set;

public class Main {

    public static Set<TestCase> generateTests(String[] args)
            throws IOException, InvalidConfigException, InterruptedException {
        if (args == null || args.length < 3) {
            throw new IllegalArgumentException("Expected config, solution, and impl directory paths");
        }

        String configContents = Files.readString(Path.of(args[0]));
        ConfigFile config = new ConfigFileParser().parse(configContents);
        BaseSetGenerator generator = new BaseSetGenerator(config.getNodes(), config.getNumRand());
        List<TestCase> baseSet = generator.genBaseSet();

        Tester tester = new Tester(config.getFuncName(), args[1], args[2], baseSet);
        tester.computeExpectedResults();
        TestResults results = tester.runTests();
        return ConciseSetGenerator.setCover(results);
    }

    public static void main(String[] args)
            throws IOException, InvalidConfigException, InterruptedException {
        Set<TestCase> tests = generateTests(args);
        for (TestCase test : tests) {
            System.out.println(test);
        }
    }
}

package main.rice.parse;

import main.rice.node.APyNode;

import java.util.List;

/**
 * Parsed configuration data for test generation.
 */
public class ConfigFile {

    private final String funcName;
    private final List<APyNode<?>> nodes;
    private final int numRand;

    public ConfigFile(String funcName, List<APyNode<?>> nodes, int numRand) {
        this.funcName = funcName;
        this.nodes = nodes;
        this.numRand = numRand;
    }

    public String getFuncName() {
        return this.funcName;
    }

    public List<APyNode<?>> getNodes() {
        return this.nodes;
    }

    public int getNumRand() {
        return this.numRand;
    }
}

package main.rice.parse;

import main.rice.node.APyNode;
import main.rice.node.PyBoolNode;
import main.rice.node.PyDictNode;
import main.rice.node.PyFloatNode;
import main.rice.node.PyIntNode;
import main.rice.node.PyListNode;
import main.rice.node.PySetNode;
import main.rice.node.PyStringNode;
import main.rice.node.PyTupleNode;

import java.util.ArrayList;
import java.util.LinkedHashMap;
import java.util.List;
import java.util.Map;

public class ConfigFileParser {

    public ConfigFile parse(String contents) throws InvalidConfigException {
        Object parsed = new JsonParser(contents).parseValue();
        if (!(parsed instanceof Map<?, ?> root)) {
            throw new InvalidConfigException("Config must be a JSON object");
        }

        String funcName = requireString(root, "fname");
        List<String> types = requireStringList(root, "types");
        List<String> exDomains = requireStringList(root, "exhaustive domain", "exDomain");
        List<String> ranDomains = requireStringList(root, "random domain", "ranDomain");
        int numRand = requireInt(root, "num random", "numRand");

        if (numRand < 0) {
            throw new InvalidConfigException("num random must be nonnegative");
        }
        if (types.size() != exDomains.size() || types.size() != ranDomains.size()) {
            throw new InvalidConfigException("types and domains must have equal lengths");
        }

        List<APyNode<?>> nodes = new ArrayList<>();
        for (int i = 0; i < types.size(); i++) {
            String typeText = types.get(i);
            ensureNoWhitespaceOrDomainChars(typeText, true);

            TypeSpec type = new TypeParser(typeText).parse();
            APyNode<?> node = buildNode(type, exDomains.get(i), ranDomains.get(i));
            nodes.add(node);
        }

        return new ConfigFile(funcName, nodes, numRand);
    }

    private static APyNode<?> buildNode(TypeSpec type, String exDomainText, String ranDomainText)
            throws InvalidConfigException {
        DomainCursor exCursor = new DomainCursor(exDomainText);
        DomainCursor ranCursor = new DomainCursor(ranDomainText);

        APyNode<?> node = buildNodeRecursive(type, exCursor, ranCursor);
        exCursor.ensureConsumed();
        ranCursor.ensureConsumed();
        return node;
    }

    private static APyNode<?> buildNodeRecursive(TypeSpec type, DomainCursor exCursor,
                                                 DomainCursor ranCursor)
            throws InvalidConfigException {
        return switch (type.kind) {
            case BOOL -> {
                PyBoolNode node = new PyBoolNode();
                node.setExDomain(parseIntegerDomain(exCursor.next(), false));
                node.setRanDomain(parseIntegerDomain(ranCursor.next(), false));
                validateBoolDomain(node.getExDomain());
                validateBoolDomain(node.getRanDomain());
                yield node;
            }
            case INT -> {
                PyIntNode node = new PyIntNode();
                node.setExDomain(parseIntegerDomain(exCursor.next(), false));
                node.setRanDomain(parseIntegerDomain(ranCursor.next(), false));
                yield node;
            }
            case FLOAT -> {
                PyFloatNode node = new PyFloatNode();
                node.setExDomain(parseNumericDomain(exCursor.next(), true, false));
                node.setRanDomain(parseNumericDomain(ranCursor.next(), true, false));
                yield node;
            }
            case STR -> {
                List<Integer> exLengths = parseIntegerDomain(exCursor.next(), true);
                List<Integer> ranLengths = parseIntegerDomain(ranCursor.next(), true);
                String exChars = parseCharDomain(exCursor.next());
                String ranChars = parseCharDomain(ranCursor.next());
                if (!exChars.equals(ranChars)) {
                    throw new InvalidConfigException("String character domains must match");
                }
                PyStringNode node = new PyStringNode(exChars);
                node.setExDomain(exLengths);
                node.setRanDomain(ranLengths);
                yield node;
            }
            case LIST -> {
                List<Integer> exLengths = parseIntegerDomain(exCursor.next(), true);
                List<Integer> ranLengths = parseIntegerDomain(ranCursor.next(), true);
                PyListNode<?> node = new PyListNode<>((APyNode) buildNodeRecursive(type.left, exCursor, ranCursor));
                node.setExDomain(exLengths);
                node.setRanDomain(ranLengths);
                yield node;
            }
            case SET -> {
                List<Integer> exLengths = parseIntegerDomain(exCursor.next(), true);
                List<Integer> ranLengths = parseIntegerDomain(ranCursor.next(), true);
                PySetNode<?> node = new PySetNode<>((APyNode) buildNodeRecursive(type.left, exCursor, ranCursor));
                node.setExDomain(exLengths);
                node.setRanDomain(ranLengths);
                yield node;
            }
            case TUPLE -> {
                List<Integer> exLengths = parseIntegerDomain(exCursor.next(), true);
                List<Integer> ranLengths = parseIntegerDomain(ranCursor.next(), true);
                PyTupleNode<?> node = new PyTupleNode<>((APyNode) buildNodeRecursive(type.left, exCursor, ranCursor));
                node.setExDomain(exLengths);
                node.setRanDomain(ranLengths);
                yield node;
            }
            case DICT -> {
                List<Integer> exLengths = parseIntegerDomain(exCursor.next(), true);
                List<Integer> ranLengths = parseIntegerDomain(ranCursor.next(), true);
                PyDictNode<?, ?> node = new PyDictNode(
                        (APyNode) buildNodeRecursive(type.left, exCursor, ranCursor),
                        (APyNode) buildNodeRecursive(type.right, exCursor, ranCursor));
                node.setExDomain(exLengths);
                node.setRanDomain(ranLengths);
                yield node;
            }
        };
    }

    private static void validateBoolDomain(List<? extends Number> domain) throws InvalidConfigException {
        for (Number value : domain) {
            int intValue = value.intValue();
            if (intValue != 0 && intValue != 1) {
                throw new InvalidConfigException("Boolean domains may only contain 0 and 1");
            }
        }
    }

    private static List<Integer> parseIntegerDomain(String token, boolean allowNegative)
            throws InvalidConfigException {
        List<? extends Number> parsed = parseNumericDomain(token, false, allowNegative);
        List<Integer> result = new ArrayList<>();
        for (Number value : parsed) {
            result.add(value.intValue());
        }
        return result;
    }

    private static List<? extends Number> parseNumericDomain(String token, boolean allowDecimal,
                                                             boolean allowNegative)
            throws InvalidConfigException {
        ensureNoWhitespaceOrDomainChars(token, false);
        if (token.startsWith("[") && token.endsWith("]")) {
            String inner = token.substring(1, token.length() - 1);
            if (inner.isEmpty()) {
                return new ArrayList<>();
            }
            String[] pieces = inner.split(",");
            List<Number> values = new ArrayList<>();
            for (String piece : pieces) {
                values.add(parseSingleNumber(piece, allowDecimal, allowNegative));
            }
            return values;
        }

        int tilde = token.indexOf('~');
        if (tilde < 0 || tilde != token.lastIndexOf('~')) {
            throw new InvalidConfigException("Invalid domain token: " + token);
        }

        Number lower = parseSingleNumber(token.substring(0, tilde), allowDecimal, allowNegative);
        Number upper = parseSingleNumber(token.substring(tilde + 1), allowDecimal, allowNegative);
        if (lower.doubleValue() > upper.doubleValue()) {
            throw new InvalidConfigException("Invalid range: " + token);
        }

        List<Number> values = new ArrayList<>();
        if (!allowDecimal) {
            for (int value = lower.intValue(); value <= upper.intValue(); value++) {
                values.add(value);
            }
        } else if (isWholeNumber(lower) && isWholeNumber(upper)) {
            for (int value = lower.intValue(); value <= upper.intValue(); value++) {
                values.add((double) value);
            }
        } else {
            double curr = lower.doubleValue();
            double upperValue = upper.doubleValue();
            while (curr <= upperValue + 1e-9) {
                values.add(curr);
                curr += 1.0;
            }
        }
        return values;
    }

    private static boolean isWholeNumber(Number value) {
        return Math.rint(value.doubleValue()) == value.doubleValue();
    }

    private static Number parseSingleNumber(String text, boolean allowDecimal, boolean allowNegative)
            throws InvalidConfigException {
        if (text.isEmpty()) {
            throw new InvalidConfigException("Empty numeric token");
        }
        if (!allowNegative && text.startsWith("-")) {
            throw new InvalidConfigException("Negative values not allowed here");
        }
        try {
            if (allowDecimal && text.contains(".")) {
                return Double.parseDouble(text);
            }
            int value = Integer.parseInt(text);
            if (allowDecimal) {
                return (double) value;
            }
            return value;
        } catch (NumberFormatException ex) {
            throw new InvalidConfigException("Invalid number: " + text);
        }
    }

    private static String parseCharDomain(String token) throws InvalidConfigException {
        ensureNoWhitespaceOrDomainChars(token, false);
        if (token.isEmpty()) {
            throw new InvalidConfigException("String character domain cannot be empty");
        }

        if (token.startsWith("[") && token.endsWith("]")) {
            String inner = token.substring(1, token.length() - 1);
            if (inner.isEmpty()) {
                throw new InvalidConfigException("String character domain cannot be empty");
            }
            String[] pieces = inner.split(",");
            StringBuilder sb = new StringBuilder();
            for (String piece : pieces) {
                String charText = stripQuotes(piece);
                if (charText.length() != 1) {
                    throw new InvalidConfigException("Each string character entry must be one character");
                }
                sb.append(charText);
            }
            return sb.toString();
        }

        String stripped = stripQuotes(token);
        if (stripped.isEmpty()) {
            throw new InvalidConfigException("String character domain cannot be empty");
        }
        return stripped;
    }

    private static String stripQuotes(String text) {
        if ((text.startsWith("\"") && text.endsWith("\""))
                || (text.startsWith("'") && text.endsWith("'"))) {
            return text.substring(1, text.length() - 1);
        }
        return text;
    }

    private static void ensureNoWhitespaceOrDomainChars(String text, boolean typeText)
            throws InvalidConfigException {
        for (int i = 0; i < text.length(); i++) {
            char c = text.charAt(i);
            if (Character.isWhitespace(c)) {
                throw new InvalidConfigException("Whitespace is not allowed");
            }
        }
        if (!typeText && (text.contains("(") || text.contains(")"))) {
            throw new InvalidConfigException("Parentheses are not allowed in domains");
        }
    }

    private static String requireString(Map<?, ?> root, String key) throws InvalidConfigException {
        Object value = root.get(key);
        if (!(value instanceof String str)) {
            throw new InvalidConfigException("Missing or invalid field: " + key);
        }
        return str;
    }

    @SuppressWarnings("unchecked")
    private static List<String> requireStringList(Map<?, ?> root, String... keys)
            throws InvalidConfigException {
        Object value = null;
        String foundKey = null;
        for (String key : keys) {
            if (root.containsKey(key)) {
                value = root.get(key);
                foundKey = key;
                break;
            }
        }
        if (!(value instanceof List<?> rawList)) {
            throw new InvalidConfigException("Missing or invalid field: " + keys[0]);
        }
        List<String> result = new ArrayList<>();
        for (Object item : rawList) {
            if (!(item instanceof String str)) {
                throw new InvalidConfigException("Invalid string array: " + foundKey);
            }
            result.add(str);
        }
        return result;
    }

    private static int requireInt(Map<?, ?> root, String... keys) throws InvalidConfigException {
        Object value = null;
        for (String key : keys) {
            if (root.containsKey(key)) {
                value = root.get(key);
                break;
            }
        }
        if (!(value instanceof Number number)) {
            throw new InvalidConfigException("Missing or invalid integer field: " + keys[0]);
        }
        if (number.doubleValue() != number.intValue()) {
            throw new InvalidConfigException("Expected integer value");
        }
        return number.intValue();
    }

    private enum TypeKind {
        BOOL, INT, FLOAT, STR, LIST, SET, TUPLE, DICT
    }

    private static final class TypeSpec {
        private final TypeKind kind;
        private final TypeSpec left;
        private final TypeSpec right;

        private TypeSpec(TypeKind kind, TypeSpec left, TypeSpec right) {
            this.kind = kind;
            this.left = left;
            this.right = right;
        }
    }

    private static final class TypeParser {
        private final String input;
        private int index;

        private TypeParser(String input) {
            this.input = input;
        }

        private TypeSpec parse() throws InvalidConfigException {
            TypeSpec type = parseType();
            if (this.index != this.input.length()) {
                throw new InvalidConfigException("Unexpected trailing type characters");
            }
            return type;
        }

        private TypeSpec parseType() throws InvalidConfigException {
            if (match("bool")) {
                return new TypeSpec(TypeKind.BOOL, null, null);
            }
            if (match("int")) {
                return new TypeSpec(TypeKind.INT, null, null);
            }
            if (match("float")) {
                return new TypeSpec(TypeKind.FLOAT, null, null);
            }
            if (match("str")) {
                return new TypeSpec(TypeKind.STR, null, null);
            }
            if (match("list(")) {
                TypeSpec inner = parseType();
                expect(')');
                return new TypeSpec(TypeKind.LIST, inner, null);
            }
            if (match("set(")) {
                TypeSpec inner = parseType();
                expect(')');
                return new TypeSpec(TypeKind.SET, inner, null);
            }
            if (match("tuple(")) {
                TypeSpec inner = parseType();
                expect(')');
                return new TypeSpec(TypeKind.TUPLE, inner, null);
            }
            if (match("dict(")) {
                TypeSpec key = parseType();
                expect(':');
                TypeSpec value = parseType();
                expect(')');
                return new TypeSpec(TypeKind.DICT, key, value);
            }
            throw new InvalidConfigException("Invalid type specification");
        }

        private boolean match(String token) {
            if (this.input.startsWith(token, this.index)) {
                this.index += token.length();
                return true;
            }
            return false;
        }

        private void expect(char token) throws InvalidConfigException {
            if (this.index >= this.input.length() || this.input.charAt(this.index) != token) {
                throw new InvalidConfigException("Malformed type specification");
            }
            this.index++;
        }
    }

    private static final class DomainCursor {
        private final String[] tokens;
        private int index;

        private DomainCursor(String text) throws InvalidConfigException {
            ensureNoWhitespaceOrDomainChars(text, false);
            this.tokens = text.split(";", -1);
            for (String token : this.tokens) {
                if (token.isEmpty()) {
                    throw new InvalidConfigException("Invalid empty domain segment");
                }
            }
        }

        private String next() throws InvalidConfigException {
            if (this.index >= this.tokens.length) {
                throw new InvalidConfigException("Too few domain segments");
            }
            return this.tokens[this.index++];
        }

        private void ensureConsumed() throws InvalidConfigException {
            if (this.index != this.tokens.length) {
                throw new InvalidConfigException("Too many domain segments");
            }
        }
    }

    private static final class JsonParser {
        private final String input;
        private int index;

        private JsonParser(String input) {
            this.input = input;
        }

        private Object parseValue() throws InvalidConfigException {
            skipWhitespace();
            if (this.index >= this.input.length()) {
                throw new InvalidConfigException("Empty JSON");
            }

            char c = this.input.charAt(this.index);
            Object value;
            if (c == '{') {
                value = parseObject();
            } else if (c == '[') {
                value = parseArray();
            } else if (c == '"') {
                value = parseString();
            } else if (c == '-' || Character.isDigit(c)) {
                value = parseNumber();
            } else if (this.input.startsWith("true", this.index)) {
                this.index += 4;
                value = Boolean.TRUE;
            } else if (this.input.startsWith("false", this.index)) {
                this.index += 5;
                value = Boolean.FALSE;
            } else if (this.input.startsWith("null", this.index)) {
                this.index += 4;
                value = null;
            } else {
                throw new InvalidConfigException("Invalid JSON");
            }

            skipWhitespace();
            if (this.index != this.input.length() && currentContainerDepth() == 0) {
                throw new InvalidConfigException("Unexpected trailing JSON content");
            }
            return value;
        }

        private int currentContainerDepth() {
            return 0;
        }

        private Map<String, Object> parseObject() throws InvalidConfigException {
            expect('{');
            skipWhitespace();
            Map<String, Object> map = new LinkedHashMap<>();
            if (peek('}')) {
                expect('}');
                return map;
            }
            while (true) {
                skipWhitespace();
                String key = parseString();
                skipWhitespace();
                expect(':');
                Object value = parseNestedValue();
                map.put(key, value);
                skipWhitespace();
                if (peek('}')) {
                    expect('}');
                    return map;
                }
                expect(',');
            }
        }

        private List<Object> parseArray() throws InvalidConfigException {
            expect('[');
            skipWhitespace();
            List<Object> list = new ArrayList<>();
            if (peek(']')) {
                expect(']');
                return list;
            }
            while (true) {
                list.add(parseNestedValue());
                skipWhitespace();
                if (peek(']')) {
                    expect(']');
                    return list;
                }
                expect(',');
            }
        }

        private Object parseNestedValue() throws InvalidConfigException {
            skipWhitespace();
            if (this.index >= this.input.length()) {
                throw new InvalidConfigException("Unexpected end of JSON");
            }
            char c = this.input.charAt(this.index);
            if (c == '{') {
                return parseObject();
            }
            if (c == '[') {
                return parseArray();
            }
            if (c == '"') {
                return parseString();
            }
            if (c == '-' || Character.isDigit(c)) {
                return parseNumber();
            }
            if (this.input.startsWith("true", this.index)) {
                this.index += 4;
                return Boolean.TRUE;
            }
            if (this.input.startsWith("false", this.index)) {
                this.index += 5;
                return Boolean.FALSE;
            }
            if (this.input.startsWith("null", this.index)) {
                this.index += 4;
                return null;
            }
            throw new InvalidConfigException("Invalid JSON value");
        }

        private String parseString() throws InvalidConfigException {
            expect('"');
            StringBuilder sb = new StringBuilder();
            while (this.index < this.input.length()) {
                char c = this.input.charAt(this.index++);
                if (c == '"') {
                    return sb.toString();
                }
                if (c == '\\') {
                    if (this.index >= this.input.length()) {
                        throw new InvalidConfigException("Invalid string escape");
                    }
                    char escaped = this.input.charAt(this.index++);
                    switch (escaped) {
                        case '"', '\\', '/' -> sb.append(escaped);
                        case 'b' -> sb.append('\b');
                        case 'f' -> sb.append('\f');
                        case 'n' -> sb.append('\n');
                        case 'r' -> sb.append('\r');
                        case 't' -> sb.append('\t');
                        case 'u' -> {
                            if (this.index + 4 > this.input.length()) {
                                throw new InvalidConfigException("Invalid unicode escape");
                            }
                            String hex = this.input.substring(this.index, this.index + 4);
                            try {
                                sb.append((char) Integer.parseInt(hex, 16));
                            } catch (NumberFormatException ex) {
                                throw new InvalidConfigException("Invalid unicode escape");
                            }
                            this.index += 4;
                        }
                        default -> throw new InvalidConfigException("Invalid string escape");
                    }
                } else {
                    sb.append(c);
                }
            }
            throw new InvalidConfigException("Unterminated string");
        }

        private Number parseNumber() throws InvalidConfigException {
            int start = this.index;
            if (this.input.charAt(this.index) == '-') {
                this.index++;
            }
            consumeDigits();
            boolean isDouble = false;
            if (this.index < this.input.length() && this.input.charAt(this.index) == '.') {
                isDouble = true;
                this.index++;
                consumeDigits();
            }
            String text = this.input.substring(start, this.index);
            try {
                return isDouble ? Double.parseDouble(text) : Integer.parseInt(text);
            } catch (NumberFormatException ex) {
                throw new InvalidConfigException("Invalid number");
            }
        }

        private void consumeDigits() throws InvalidConfigException {
            int start = this.index;
            while (this.index < this.input.length() && Character.isDigit(this.input.charAt(this.index))) {
                this.index++;
            }
            if (start == this.index) {
                throw new InvalidConfigException("Invalid number");
            }
        }

        private boolean peek(char expected) {
            return this.index < this.input.length() && this.input.charAt(this.index) == expected;
        }

        private void expect(char expected) throws InvalidConfigException {
            skipWhitespace();
            if (!peek(expected)) {
                throw new InvalidConfigException("Invalid JSON");
            }
            this.index++;
        }

        private void skipWhitespace() {
            while (this.index < this.input.length()
                    && Character.isWhitespace(this.input.charAt(this.index))) {
                this.index++;
            }
        }
    }
